const item = $input.item.json;
const body = item.body || item;
if (!body || typeof body !== 'object') {
  throw new Error('No se recibio body valido. Recibido: ' + JSON.stringify(item).substring(0, 200));
}
const required = ['brand_id', 'product_id', 'selfie_base64', 'product_image_url', 'prompt'];
const missing = required.filter(f => !body[f]);
if (missing.length > 0) {
  throw new Error('Faltan campos: ' + missing.join(', ') + '. Body recibido: ' + JSON.stringify(Object.keys(body)));
}
if (body.selfie_base64.length < 100) {
  throw new Error('selfie_base64 invalido o muy corto (' + body.selfie_base64.length + ' chars)');
}
const urlRegex = /^https?:\/\/.+/;
if (!urlRegex.test(body.product_image_url)) {
  throw new Error('product_image_url no es URL valida: ' + body.product_image_url);
}
const now = new Date();
const timestamp = now.toISOString();
const timestamp_safe = timestamp.replace(/[:.]/g, '-');
return { json: { brand_id: body.brand_id, product_id: body.product_id, selfie_base64: body.selfie_base64, product_image_url: body.product_image_url, prompt: body.prompt, timestamp, timestamp_safe } };

const data = $('Validar Input').item.json;
const upload = $input.item.json;
if (!upload.success || !upload.url) {
  throw new Error('Error al subir selfie: ' + JSON.stringify(upload));
}
return { json: { brand_id: data.brand_id, product_id: data.product_id, product_image_url: data.product_image_url, timestamp: data.timestamp, timestamp_safe: data.timestamp_safe, full_prompt: data.prompt, selfie_url: upload.url, selfie_base64: data.selfie_base64 } };

const r = $input.item.json;
const prev = $('Preparar Prompt Gemini').item.json;
if (!r.choices?.[0]?.message) throw new Error('Respuesta invalida de Gemini: ' + JSON.stringify(r).substring(0,300));
const msg = r.choices[0].message;
let b64 = null;
if (Array.isArray(msg.images) && msg.images.length > 0) {
  const img = msg.images[0];
  if (img.image_url?.url) { const m = img.image_url.url.match(/base64,(.+)/s); if (m) b64 = m[1]; }
}
if (!b64 && Array.isArray(msg.content)) {
  for (const block of msg.content) {
    if (block.type === 'image_url' && block.image_url?.url?.startsWith('data:image')) {
      const m = block.image_url.url.match(/base64,(.+)/s); if (m) b64 = m[1];
    }
    if (block.type === 'image' && block.source?.data) b64 = block.source.data;
    if (block.type === 'inline_data' && block.inline_data?.data) b64 = block.inline_data.data;
  }
}
if (!b64 && typeof msg.content === 'string') {
  const m = msg.content.match(/data:image\/[^;]+;base64,([A-Za-z0-9+\/=\s]+)/s);
  if (m) b64 = m[1];
}
if (!b64) throw new Error('No se encontro imagen. Estructura: ' + JSON.stringify({keys:Object.keys(msg), hasImages:!!msg.images, contentType:typeof msg.content}).substring(0,200));

// Detectar dimensiones de la selfie original desde su base64
let selfieWidth = 0, selfieHeight = 0;
try {
  const sb = Buffer.from(prev.selfie_base64.replace(/\s+/g,''), 'base64');
  // JPEG: buscar SOF marker (0xFF 0xC0 o 0xFF 0xC2)
  for (let i = 0; i < sb.length - 8; i++) {
    if (sb[i] === 0xFF && (sb[i+1] === 0xC0 || sb[i+1] === 0xC2)) {
      selfieHeight = (sb[i+5] << 8) | sb[i+6];
      selfieWidth  = (sb[i+7] << 8) | sb[i+8];
      break;
    }
  }
  // PNG: dimensiones en bytes 16-23
  if (selfieWidth === 0 && sb[1] === 0x50 && sb[2] === 0x4E && sb[3] === 0x47) {
    selfieWidth  = (sb[16] << 24) | (sb[17] << 16) | (sb[18] << 8) | sb[19];
    selfieHeight = (sb[20] << 24) | (sb[21] << 16) | (sb[22] << 8) | sb[23];
  }
} catch(e) { /* si falla, el backend sube sin recortar */ }

return { json: {
  brand_id: prev.brand_id,
  product_id: prev.product_id,
  timestamp: prev.timestamp,
  timestamp_safe: prev.timestamp_safe,
  selfie_url: prev.selfie_url,
  selfie_width: selfieWidth,
  selfie_height: selfieHeight,
  generated_image_base64: b64.replace(/\s+/g,'')
}};
